"use strict";(self.webpackChunkportfolio=self.webpackChunkportfolio||[]).push([[5323],{5415:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"Introducci\xf3n","metadata":{"permalink":"/portfolio/es/blog/Introducci\xf3n","source":"@site/i18n/es/docusaurus-plugin-content-blog/2023-01-21-introduction/index.md","title":"Introducci\xf3n","description":"Me gustar\xeda tomar un caf\xe9 contigo, sentarme a dibujar y pensar.","date":"2023-01-21T00:00:00.000Z","formattedDate":"21 de enero de 2023","tags":[],"readingTime":0.435,"hasTruncateMarker":false,"authors":[{"name":"Juan Carlos","title":"Arroyo Sosa","url":"https://github.com/jcarroyos","imageURL":"https://avatars.githubusercontent.com/u/4398275","key":"jcarroyos"}],"frontMatter":{"slug":"Introducci\xf3n","title":"Introducci\xf3n","authors":["jcarroyos"],"tags":[]},"nextItem":{"title":"Virtual enviroments at MMGP","permalink":"/portfolio/es/blog/virtual-enviroment-unal"}},"content":"Me gustar\xeda tomar un caf\xe9 contigo, sentarme a dibujar y pensar.\\n\\nD\xe9jame decirte que si expusiera mis trabajos de los \xfaltimos a\xf1os, sin duda ser\xeda una exposici\xf3n, una invitaci\xf3n a despertar tu curiosidad por las arquitecturas de informaci\xf3n, diagramas, visualizaciones de datos e interfaces de usuario, con notas explicativas sobre temas sociales complejos.\\n\\nEl trabajo duro ser\xeda recordar todos los nombres de amigos, f\xedsicos, economistas, comunicadores, polit\xf3logos, soci\xf3logos, l\xedderes sociales y defensores de los derechos humanos con los que he tenido el honor de sentarme a pensar."},{"id":"virtual-enviroment-unal","metadata":{"permalink":"/portfolio/es/blog/virtual-enviroment-unal","source":"@site/blog/2021-06-30-virtual-enviroment/index.md","title":"Virtual enviroments at MMGP","description":"How do museums take advantage of information technologies and virtual environments? Well, based on this question, a pedagogical experience was created for the fifth, sixth and seventh cohorts of the Master\'s Degree in Museology and Heritage Management at the National University of Colombia, the name of the course is, ... to no one\'s surprise \ud83d\ude0c, INFORMATION TECHNOLOGIES AND VIRTUAL ENVIRONMENTS.","date":"2021-06-30T00:00:00.000Z","formattedDate":"30 de junio de 2021","tags":[{"label":"tics","permalink":"/portfolio/es/blog/tags/tics"},{"label":"museology","permalink":"/portfolio/es/blog/tags/museology"}],"readingTime":0.695,"hasTruncateMarker":false,"authors":[{"name":"Juan Carlos","title":"Arroyo Sosa","url":"https://github.com/jcarroyos","imageURL":"https://avatars.githubusercontent.com/u/4398275","key":"jcarroyos"}],"frontMatter":{"slug":"virtual-enviroment-unal","title":"Virtual enviroments at MMGP","authors":["jcarroyos"],"tags":["tics","museology"]},"prevItem":{"title":"Introducci\xf3n","permalink":"/portfolio/es/blog/Introducci\xf3n"},"nextItem":{"title":"Infographics at UTolima","permalink":"/portfolio/es/blog/infographics-utolima"}},"content":"How do museums take advantage of information technologies and virtual environments? Well, based on this question, a pedagogical experience was created for the fifth, sixth and seventh cohorts of the Master\'s Degree in [Museology and Heritage Management at the National University of Colombia](http://artes.bogota.unal.edu.co/programas-academicos/posgrado/maestria/museologia), the name of the course is, ... to no one\'s surprise \ud83d\ude0c, INFORMATION TECHNOLOGIES AND VIRTUAL ENVIRONMENTS.\\n\\nThis course was shared with other teachers, in the first cohorts it was taught together with Philippe Boland and Ana Mar\xeda Moreno Ballesteros. The course of the year 2021 I worked together with [Paola Parra](https://www.linkedin.com/in/paoltricia).\\n\\n[Click here to see the course program (in spanish)](./program-mmgp-jcarroyos-paoltricia.pdf)\\n\\n## Class pics\\n\\n:::note Ideation process\\n![registro de clase mmgp](./mmgp-1.jpg)\\n\\n:::\\n\\n:::note Dashboard snapshot\\n![registro de clase mmgp](./mmgp-2.jpg)\\n:::\\n\\n:::note structuring information workshop\\n![registro de clase mmgp](./mmgp-3.jpg)\\n:::\\n\\n:::note coding\\n![registro de clase mmgp](./mmgp-4.jpg)\\n:::"},{"id":"infographics-utolima","metadata":{"permalink":"/portfolio/es/blog/infographics-utolima","source":"@site/blog/2021-01-30-infographics/index.md","title":"Infographics at UTolima","description":"From 2016 to 2021 I had the beautiful experience in the role of professor for Infographics at University of Tolima. I learned and shared a lot during those years of teaching.","date":"2021-01-30T00:00:00.000Z","formattedDate":"30 de enero de 2021","tags":[{"label":"infographics","permalink":"/portfolio/es/blog/tags/infographics"}],"readingTime":0.785,"hasTruncateMarker":false,"authors":[{"name":"Juan Carlos","title":"Arroyo Sosa","url":"https://github.com/jcarroyos","imageURL":"https://avatars.githubusercontent.com/u/4398275","key":"jcarroyos"}],"frontMatter":{"slug":"infographics-utolima","title":"Infographics at UTolima","authors":["jcarroyos"],"tags":["infographics"]},"prevItem":{"title":"Virtual enviroments at MMGP","permalink":"/portfolio/es/blog/virtual-enviroment-unal"}},"content":"From 2016 to 2021 I had the beautiful experience in the role of professor for **Infographics** at [University of Tolima](https://ut.edu.co/). I learned and shared a lot during those years of teaching.\\n\\nWith a practical approach, this course presents the evolution of infographics, the workshop focus on the core questions:\\n\\n- what is infographics?\\n- what are infographics for?\\n- and how we can made infographics?\\n\\nBased on the idea that infographics in the field of communication can be understood as a journalistic genre, during the course we explore the possibilities of creation and think on the theoretical field of image research and visual studies.\\n\\n## Class pics\\n\\n:::note Student project analog infographics\\n![registro de clase infograf\xeda](./utolima-infografia-1.jpg)\\n:::\\n\\n:::note Data collecting in public space\\n![registro de clase infograf\xeda](./utolima-infografia-2.jpg)\\n:::\\n\\n:::note Data collecting in public space\\n![registro de clase infograf\xeda](./utolima-infografia-3.jpg)\\n:::\\n\\n:::note Workshop at https://tell.com.co/\\n![registro de clase infograf\xeda](./utolima-infografia-4.jpg)\\n:::\\n\\n:::note Workshop at https://www.lasillavacia.com/\\n![registro de clase infograf\xeda](./utolima-infografia-5.jpg)\\n:::"}]}')}}]);